const threshold = parseFloat($env.CHURN_ALERT_THRESHOLD || 20);
const cohorts = $input.all().map(i => {
  const d = i.json;
  const size = parseInt(d.size || 1);
  const c30 = parseFloat(d.churned_30d || 0), c60 = parseFloat(d.churned_60d || 0), c90 = parseFloat(d.churned_90d || 0);
  const churn_30_pct = ((c30 / size) * 100).toFixed(1);
  const churn_90_pct = (((c30 + c60 + c90) / size) * 100).toFixed(1);
  const is_at_risk = parseFloat(churn_30_pct) >= threshold;
  return { ...d, churn_30_pct: parseFloat(churn_30_pct), churn_90_pct: parseFloat(churn_90_pct), is_at_risk };
}).sort((a, b) => b.churn_30_pct - a.churn_30_pct);
const at_risk = cohorts.filter(c => c.is_at_risk);
return [{ json: { date: new Date().toISOString().slice(0, 10), total_cohorts: cohorts.length, at_risk_count: at_risk.length, threshold_pct: threshold, cohorts, at_risk } }];

